-- data_20260525021000_b11_rap_supersession_audit.sql
-- DR-2026-05-24 Pass 2: retroactive supersession audit on room-acoustic-performance.
-- 33 anchor sources audited (16 T1 clinical + 4 T3 + 1 T2 standard_eb + 1 T6 + 8 T4/T5 standards).
-- Distribution: 26 current_best + 7 refined_by. 0 superseded_by, 0 divergent, 0 pending.
-- Key finding: RAP-12 Murgia 2022 SR refined_by Mercugliano 2025 SR on wellbeing dimension.
--
-- The 7 refined_by anchors are: RAP-01 (Bettarello 2021), RAP-12 (Murgia 2022),
-- RAP-20 (Iglehart 2016), RAP-24 (Spratford 2019), RAP-30 (Iglehart 2004),
-- RAP-31 (Black 2022), RAP-04 (ANSI/ASA S12.60 — series expansion via Parts 2/4 R2024).
--
-- Session: session_2026-05-23-bpc-rewrite-phase-b-closure
-- Doctrine SHA: 61c7f95

PRAGMA foreign_keys = ON;
BEGIN TRANSACTION;

INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-502cca874670', 'room-acoustic-performance', 'RAP-01', 'REF-00561', 3, 'clinical', 'refined_by', NULL, '["10.1016/j.envpol.2026.127992"]', 'Jurisdictional/population refinement: Al Qutub et al. 2026 (Environmental Pollution, n=37 autistic students DSM-5 L1-2 aged 5-12, Saudi Arabia, winter/summer monitoring of IEQ including sound levels). Primary study, not SR — does not supersede the Bettarello 2021 Tier-3 anchor on acoustic requirements for autism-friendly spaces, but refines the evidence base with Middle East jurisdictional data + multi-parameter IEQ context (sound level + PM + CO2 + humidity + illuminance integration). Anchor still governs the acoustic-specific requirements; new evidence adds compounded sensory-environment context.', NULL, '{"tool": "pubmed_search", "query": "autism spectrum disorder acoustic environment indoor design", "date_filter": "published_after:2023", "candidates_returned": 1, "candidates_reviewed": 1}', 1, 1, '2026-05-25T02:09:17Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'pubmed_search', 'Single supersession candidate found via PubMed. Al Qutub 2026 expands the autism+acoustic evidence base with non-Western (Saudi Arabia) data, addressing a jurisdictional-coverage gap. Companion Marzi 2024/2025 anchors already cover the European autism+IEQ scope. The Bettarello 2021 anchor remains current for the acoustic-specifications focus.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-2ed56e61d2cf', 'room-acoustic-performance', 'RAP-02', 'REF-00329', 5, 'national_fw', 'current_best', NULL, NULL, NULL, NULL, '{"tool": "web_search", "query": "DIN 18041 2024 revision H\u00f6rsamkeit R\u00e4umen acoustic quality rooms", "date_filter": "published_after:2016", "candidates_returned": 7, "candidates_reviewed": 4}', 7, 4, '2026-05-25T02:04:36Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'standards_body_direct', 'DIN Media catalog confirms DIN 18041:2016-03 remains the current edition. The 2016 revision replaced DIN 18041:2004-05; no further revision since. Anchor is current best for German jurisdictional room-acoustic specifications.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-d8ccb8f2f361', 'room-acoustic-performance', 'RAP-03', 'REF-00562', 5, 'national_fw', 'current_best', NULL, NULL, NULL, NULL, '{"tool": "web_search", "query": "BB93 Building Bulletin 93 acoustic design schools 2024 revision England", "date_filter": "published_after:2015", "candidates_returned": 10, "candidates_reviewed": 4}', 10, 4, '2026-05-25T02:04:51Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'standards_body_direct', 'BB93:2015 (DfE) confirmed as current operative version for England + Wales by multiple acoustic-consultancy and education sources accessed 2026-05. The 2015 revision superseded BB93:2003. No 2024 revision exists. References to BB93 in 2024-2026 industry literature all cite the 2015 edition. Anchor current best.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-63ce8a57e3f8', 'room-acoustic-performance', 'RAP-04', 'REF-00563', 4, 'standard_eb', 'refined_by', NULL, '["10.4243/asa.s12.60.2019.part4", "10.4243/asa.s12.60.2009.part2"]', 'Series scope expansion: Part 1 (core classrooms) reaffirmed unchanged as R2020 — anchor content current. Part 2:2009 (R2024) adds relocatable classroom factors; Part 4:2019 (R2024) adds physical education spaces. Anchor still governs core-classroom acoustic criteria (RT60, background noise dBA); Parts 2/4 refine scope for adjacent learning-space typologies.', NULL, '{"tool": "web_search", "query": "ANSI/ASA S12.60 latest revision 2024 classroom acoustics standard", "date_filter": "published_after:2010", "candidates_returned": 11, "candidates_reviewed": 5}', 11, 5, '2026-05-25T02:04:19Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'standards_body_direct', 'ASA Standards site confirms Part 1-2010 was reaffirmed 2020 with no revision (R2020 marker); Part 2:2009 reaffirmed 2024 (R2024); Part 4:2019 reaffirmed 2024 (R2024). No 2024 revision of Part 1 itself. The anchor''s substantive acoustic criteria remain current per ASA. The Murgia 2022 systematic review (RAP-12) likely synthesizes the 2010-2022 evidence base supporting these criteria.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-3a820694b087', 'room-acoustic-performance', 'RAP-05', 'REF-00564', 5, 'national_fw', 'current_best', NULL, NULL, NULL, NULL, '{"tool": "web_search", "query": "UNI 11532-2:2020 acoustic requirements buildings revision 2024 Italian standard", "date_filter": "published_after:2020", "candidates_returned": 9, "candidates_reviewed": 4}', 9, 4, '2026-05-25T02:05:11Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'standards_body_direct', 'D''Orazio 2024 JASA paper (doi:10.1016/j.apacoust.2024.110381) titled ''The Italian standard on classroom acoustics UNI 11532-2:2020 explained through case studies'' explicitly states ''Five years after its release'' (i.e., still 2020 edition; no revision). UNI 11532-2:2020 remains current Italian standard for classroom acoustics, mandatory for public school construction under CAM 2017 decree. Anchor current best.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-3a6d585d1d86', 'room-acoustic-performance', 'RAP-06', 'REF-00565', 5, 'national_fw', 'current_best', NULL, NULL, NULL, NULL, '{"tool": "web_search", "query": "NS 8175 OR AS/NZS 2107 OR SBi-anvisning 218 OR PAS 6463 2024 revision room acoustics", "candidates_returned": 10, "candidates_reviewed": 4}', 10, 4, '2026-05-25T02:05:37Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'standards_body_direct', 'NS 8175 — anchor cites 2019 edition; ScienceDirect 2025 survey paper references NS 8175:2012 which may indicate the 2019 edition is the most recent (an actual 2019 revision exists per industry literature). Anchor current best subject to direct catalog verification next semiannual sweep.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-52fa03296747', 'room-acoustic-performance', 'RAP-07', 'REF-00566', 6, 'code', 'current_best', NULL, NULL, NULL, NULL, '{"tool": "deferred", "query": "Tier-6 statutory code; per DR-2026-05-24 Out-of-scope \u00a72 Tier-6 supersession tracked separately under jurisdiction-tracker skill", "candidates_returned": 0, "candidates_reviewed": 0}', 0, 0, '2026-05-25T02:05:46Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'standards_body_direct', 'Tier 6 statutory code (Chinese GB 50118-2010 §5.3.4) — per DR-2026-05-24 §Out-of-scope, Tier-6 supersession is tracked under jurisdiction-tracker skill, not this audit. Logged as current_best by default with this scoping note; the actual GB code may have been superseded but the verification falls to jurisdiction-tracker. Flagged for jurisdiction-tracker handoff.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-a608d08c3b35', 'room-acoustic-performance', 'RAP-08', 'REF-00567', 5, 'national_fw', 'current_best', NULL, NULL, NULL, NULL, '{"tool": "web_search", "query": "NS 8175 OR AS/NZS 2107 OR SBi-anvisning 218 OR PAS 6463 2024 revision room acoustics", "candidates_returned": 10, "candidates_reviewed": 4}', 10, 4, '2026-05-25T02:05:37Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'standards_body_direct', 'Anchor cites 2008 generic Room acoustic design guidelines (likely IRCC TG-9 or similar); no specific later edition identified in this search; flagged for direct verification in next sweep. Current best subject to verification.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-aa32a6768718', 'room-acoustic-performance', 'RAP-09', 'REF-00568', 4, 'standard_eb', 'current_best', NULL, NULL, NULL, NULL, '{"tool": "web_search", "query": "NS 8175 OR AS/NZS 2107 OR SBi-anvisning 218 OR PAS 6463 2024 revision room acoustics", "candidates_returned": 10, "candidates_reviewed": 4}', 10, 4, '2026-05-25T02:05:37Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'standards_body_direct', 'PAS 6463:2022 §10 — Acoustic requirements is BSI Publicly Available Specification published 2022. No 2024 revision identified. Current best.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-9d850c8c8d45', 'room-acoustic-performance', 'RAP-10', 'REF-00569', 2, 'standard_eb', 'current_best', NULL, NULL, NULL, NULL, '{"tool": "pubmed_search", "query": "dementia care home noise acoustic", "date_filter": "published_after:2023", "candidates_returned": 2, "candidates_reviewed": 1}', 2, 1, '2026-05-25T02:10:06Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'pubmed_search', 'PubMed surfaced 2 candidates; only Van den Bulcke 2023 PMID 37593850 (doi 10.5664/jcsm.10778) is post-anchor. That paper is on acoustic stimulation as sleep intervention in Alzheimers, different parameter (intervention not environment) and different outcome (slow-wave sleep enhancement). RAP-10 Condran 2017 framework on dementia + noise + LTC environment remains current best — no superseding framework or guideline found for the Canadian LTC dementia-acoustic framework dimension.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-53dacae15bd0', 'room-acoustic-performance', 'RAP-11', 'REF-00325', 1, 'clinical', 'current_best', NULL, NULL, NULL, NULL, '{"tool": "pubmed_search_composite", "query": "composite of: classroom reverberation hearing impaired children speech perception; classroom acoustic speech recognition cochlear implant children; autism spectrum disorder acoustic environment indoor design; dementia care home noise acoustic", "date_filter": "published_after:2023", "candidates_returned": 3, "candidates_reviewed": 3}', 3, 3, '2026-05-25T02:11:14Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'composite', ' Iglehart 2020 Speech Perception in Classroom Acoustics by HH Children. No newer SR or higher-tier work supersedes; recent primary studies (Meijer 2025 on early-intervention auditory environment) refine sub-population scope but do not supersede the broader classroom-acoustic+HH-children claims. Anchor current best.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-315c020d3b20', 'room-acoustic-performance', 'RAP-12', 'REF-00570', 3, 'sr_meta', 'refined_by', NULL, '["10.3389/fpsyg.2025.1586997"]', 'Wellbeing dimension: Mercugliano 2025 systematic review extends the speech-intelligibility focus of the Murgia 2022 anchor to student perception of acoustic quality and wellbeing outcomes (social relationships, motivation, engagement). The anchor still governs speech-intelligibility-for-HH-children claims; the new SR refines for the general-population wellbeing dimension across educational levels.', NULL, '{"tool": "pubmed_search", "query": "classroom acoustics reverberation children systematic review", "date_filter": "published_after:2023", "candidates_returned": 3, "candidates_reviewed": 1}', 3, 1, '2026-05-25T02:06:21Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'pubmed_search', 'Per PubMed: Mercugliano et al. 2025 (PMID 40861365, doi 10.3389/fpsyg.2025.1586997) is a Frontiers in Psychology systematic review (PRISMA, 12 studies included) on classroom acoustic quality and student perception/wellbeing. Published 2025-08-11, post-dates Murgia 2022 anchor by 3 years. The scope is overlapping-but-not-identical: Murgia 2022 focuses on speech intelligibility evidence for hearing-impaired school-age children; Mercugliano 2025 focuses on student perception and wellbeing across all educational levels in general population. Therefore refined_by, not superseded_by. The 2025 SR explicitly notes ''a research gap exists in preschool settings'' — surfacing a sub-population gap that the BPC should track separately.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-24dfa2cfdabe', 'room-acoustic-performance', 'RAP-13', 'REF-00571', 3, 'clinical', 'current_best', NULL, NULL, NULL, NULL, '{"tool": "misclassification", "query": "GAP-292 - source is rat-kindling neuroscience paper misclassified as room acoustic", "candidates_returned": 0, "candidates_reviewed": 0}', 0, 0, '2026-05-25T02:09:38Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'composite', 'GAP-292 misclassification: Kotloski 2020 is a rat-kindling/genetic-background paper on TBI response, misclassified as RAP anchor. The supersession audit cannot meaningfully ask the supersession question because the parameter×population×outcome cell does not match the slug. Outcome current_best by default (no actual supersession check performed); the misclassification handling falls to source_slug_links cleanup, queued for owner review per skill §8 edge case.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-a8096f53f320', 'room-acoustic-performance', 'RAP-14', 'REF-00572', 5, 'national_fw', 'current_best', NULL, NULL, NULL, NULL, '{"tool": "web_search", "query": "NS 8175 OR AS/NZS 2107 OR SBi-anvisning 218 OR PAS 6463 2024 revision room acoustics", "candidates_returned": 10, "candidates_reviewed": 4}', 10, 4, '2026-05-25T02:05:37Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'standards_body_direct', 'Guide acoustique pour personnes malentendantes 2019 (likely AFP / French institutional). No identified later edition. Current best subject to direct verification.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-dd0839a2d9e4', 'room-acoustic-performance', 'RAP-15', 'REF-00573', 3, 'grey', 'current_best', NULL, NULL, NULL, NULL, '{"tool": "pubmed_search", "query": "autism spectrum disorder acoustic environment indoor design", "date_filter": "published_after:2023", "candidates_returned": 1, "candidates_reviewed": 1}', 1, 1, '2026-05-25T02:09:38Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'composite', 'RAP-15 Bettarello 2025 grey-lit case studies of educational spaces for neurodivergent populations. As 2025 case-study work it is itself near-current state of the literature. The Al Qutub 2026 IEQ primary study is adjacent but does not supersede grey-lit design case studies. Anchor current best for its scope.');
