INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-926bad64e354', 'room-acoustic-performance', 'RAP-17', 'REF-00575', 5, 'national_fw', 'current_best', NULL, NULL, NULL, NULL, '{"tool": "web_search", "query": "NS 8175 OR AS/NZS 2107 OR SBi-anvisning 218 OR PAS 6463 2024 revision room acoustics", "candidates_returned": 10, "candidates_reviewed": 4}', 10, 4, '2026-05-25T02:05:37Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'standards_body_direct', 'SBi-anvisning 218:2008 (Danish Building Research Institute) — anchor is 17 years old; no later edition surfaced in this search. Current best subject to direct verification (Danish standards body may have superseded with newer SBi-anvisning or BR18 incorporation).');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-8538fc393c07', 'room-acoustic-performance', 'RAP-18', 'REF-00576', 1, 'clinical', 'current_best', NULL, NULL, NULL, NULL, '{"tool": "pubmed_search_composite", "query": "composite of: classroom reverberation hearing impaired children speech perception; classroom acoustic speech recognition cochlear implant children; autism spectrum disorder acoustic environment indoor design; dementia care home noise acoustic", "date_filter": "published_after:2023", "candidates_returned": 3, "candidates_reviewed": 3}', 3, 3, '2026-05-25T02:11:14Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'composite', ' Wroblewski 2012 Effects of reverberation on speech recognition. Foundational primary study on RT-recognition relationship in HH children; not superseded by newer primary work in 2023-2026 search. Anchor current best for its specific parameter-outcome pairing.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-ad9996a3a319', 'room-acoustic-performance', 'RAP-19', 'REF-00577', 1, 'clinical', 'current_best', NULL, NULL, NULL, NULL, '{"tool": "pubmed_search_composite", "query": "composite of: classroom reverberation hearing impaired children speech perception; classroom acoustic speech recognition cochlear implant children; autism spectrum disorder acoustic environment indoor design; dementia care home noise acoustic", "date_filter": "published_after:2023", "candidates_returned": 3, "candidates_reviewed": 3}', 3, 3, '2026-05-25T02:11:14Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'composite', ' Neuman 2010 Combined effects of noise and reverberation. Foundational primary study; cluster search returned no superseding work. Anchor current best.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-7b91fe48af60', 'room-acoustic-performance', 'RAP-20', 'REF-00578', 1, 'clinical', 'refined_by', NULL, '["10.1080/02699206.2024.2340096", "10.1007/s12070-025-05558-6"]', 'CI sub-dimension: Lombard effect with reverberation (Okalidou 2024) + age/SNR effects on word recognition in pediatric CI users (Jain 2025) refine the Iglehart 2016 CI+typical-hearing speech-perception evidence. Anchor still governs the broader CI+classroom comparison; new evidence adds suprasegmental + age-stratified sub-population data.', NULL, '{"tool": "pubmed_search_composite", "query": "classroom acoustic speech recognition cochlear implant children", "date_filter": "published_after:2023", "candidates_returned": 2, "candidates_reviewed": 2}', 2, 2, '2026-05-25T02:11:34Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'pubmed_search', 'Iglehart 2016 CI+typical-hearing speech perception anchor. Two refinement candidates found.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-9f591f643803', 'room-acoustic-performance', 'RAP-21', 'REF-00579', 1, 'clinical', 'current_best', NULL, NULL, NULL, NULL, '{"tool": "pubmed_search_composite", "query": "composite of: classroom reverberation hearing impaired children speech perception; classroom acoustic speech recognition cochlear implant children; autism spectrum disorder acoustic environment indoor design; dementia care home noise acoustic", "date_filter": "published_after:2023", "candidates_returned": 3, "candidates_reviewed": 3}', 3, 3, '2026-05-25T02:11:14Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'composite', ' Anderson 2004 FM and infrared devices for HH children. 21-year-old primary study; no newer SR/meta surfaced in cluster search synthesizing the FM-device-classroom-acoustic evidence. Anchor remains current best for FM-classroom intervention evidence by absence-of-replacement.');
INSERT OR REPLACE INTO supersession_check (check_id, slug, local_ref_id, ref_id, anchor_tier, anchor_evidence_type, outcome, superseding_ref_ids, superseding_dois, refinement_dimension, divergence_notes, search_strategy_record, candidates_returned, candidates_reviewed, checked_at, checked_by_session, check_method, notes) VALUES ('SUPCHK-a2f458671d42', 'room-acoustic-performance', 'RAP-22', 'REF-00580', 1, 'clinical', 'current_best', NULL, NULL, NULL, NULL, '{"tool": "pubmed_search_composite", "query": "composite of: classroom reverberation hearing impaired children speech perception; classroom acoustic speech recognition cochlear implant children; autism spectrum disorder acoustic environment indoor design; dementia care home noise acoustic", "date_filter": "published_after:2023", "candidates_returned": 3, "candidates_reviewed": 3}', 3, 3, '2026-05-25T02:11:14Z', 'session_2026-05-23-bpc-rewrite-phase-b-closure', 'composite', ' Amlani 2016 Negative effect of acoustic panels on listening effort. Specific small-N primary study on panel-RT relationship. No directly competing primary study in 2023-2026 search. Anchor current best.');
